      "name": "Correlated subquery",
      "sql": "SELECT recorded_on\nFROM weather w\nWHERE temperature > (\n  SELECT temperature\n  FROM weather prev\n  WHERE prev.recorded_on = date(w.recorded_on, '-1 day')\n)\nORDER BY recorded_on;",
