      "sql": "WITH totals AS (\n  SELECT student,\n         SUM(credits * grade_point) AS weighted_sum,\n         SUM(credits)               AS total_credits\n  FROM enrollments\n  GROUP BY student\n)\nSELECT student,\n       ROUND(weighted_sum / total_credits, 2) AS gpa\nFROM totals\nORDER BY gpa DESC, student;",
